func withRiskMeta(risk string, readOnly bool) mcplib.ToolOption {
	return func(tool *mcplib.Tool) {
		if tool.Meta == nil {
			tool.Meta = &mcplib.Meta{}
		}
		if tool.Meta.AdditionalFields == nil {
			tool.Meta.AdditionalFields = map[string]any{}
		}
		tool.Meta.AdditionalFields["mcp:risk"] = risk
		tool.Meta.AdditionalFields["mcp:read-only"] = readOnly
	}
}

